import React from 'react';
import { Link as RouterLink } from 'react-router-dom';

export default function Link(props) {
  if (props.link.url.includes('http'))
    return (
      <a className="linky" href={props.link.url}>
        {props.link.title}
      </a>
    );
  else {
    return (
      <RouterLink className="linky" to={props.link.url}>
        {props.link.title}
      </RouterLink>
    );
  }
}



